CREATE INDEX idx_real_expenses_created_by_profile_id ON public.real_expenses USING btree (created_by_profile_id);
CREATE INDEX idx_real_expenses_estimated_budget_id ON public.real_expenses USING btree (estimated_budget_id) WHERE (estimated_budget_id IS NOT NULL);
