-- Row Level Security — enable
-- ============================================================================
ALTER TABLE "bank_balances" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "budget_transfers" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "estimated_budgets" ENABLE ROW LEVEL SECURITY;
