ALTER TABLE "monthly_recaps" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "piggy_bank" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "profiles" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "real_expenses" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "real_income_entries" ENABLE ROW LEVEL SECURITY;
