-- ============================================================================
-- Row Level Security — policies
-- ============================================================================
CREATE POLICY "Users can update their own bank balance"
  ON "bank_balances"
  FOR ALL
  USING ((auth.uid() = profile_id));
CREATE POLICY "Users can view their own bank balance"
  ON "bank_balances"
  FOR SELECT
  USING ((auth.uid() = profile_id));
CREATE POLICY "Users can delete their own budget transfers"
  ON "budget_transfers"
  FOR DELETE
  USING (((profile_id = auth.uid()) OR (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can insert their own budget transfers"
  ON "budget_transfers"
  FOR INSERT
  WITH CHECK ((((profile_id = auth.uid()) AND (group_id IS NULL)) OR ((group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid()))) AND (profile_id IS NULL))));
CREATE POLICY "Users can update their own budget transfers"
  ON "budget_transfers"
  FOR UPDATE
  USING (((profile_id = auth.uid()) OR (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can view their own budget transfers"
  ON "budget_transfers"
  FOR SELECT
  USING (((profile_id = auth.uid()) OR (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Group members can manage group budgets"
  ON "estimated_budgets"
  FOR ALL
  USING (((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can manage their own budgets"
  ON "estimated_budgets"
  FOR ALL
  USING ((profile_id = auth.uid()));
CREATE POLICY "Group members can manage group estimated incomes"
  ON "estimated_incomes"
  FOR ALL
  USING (((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can manage their own estimated incomes"
  ON "estimated_incomes"
  FOR ALL
  USING ((profile_id = auth.uid()));
CREATE POLICY "Group members can manage their group contributions"
  ON "group_contributions"
  FOR ALL
  USING ((group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid()))));
CREATE POLICY "Users can view contributions for their own group"
  ON "group_contributions"
  FOR SELECT
  USING ((EXISTS ( SELECT 1
   FROM profiles
  WHERE ((profiles.id = auth.uid()) AND (profiles.group_id = group_contributions.group_id)))));
CREATE POLICY "Creators can delete their groups"
  ON "groups"
  FOR DELETE
  TO authenticated
  USING ((creator_id = auth.uid()));
CREATE POLICY "Creators can update their groups"
  ON "groups"
  FOR UPDATE
  TO authenticated
  USING ((creator_id = auth.uid()));
CREATE POLICY "Users can create groups"
  ON "groups"
  FOR INSERT
  TO authenticated
  WITH CHECK ((creator_id = auth.uid()));
CREATE POLICY "Users can view all groups"
  ON "groups"
  FOR SELECT
  TO authenticated
  USING (true);
CREATE POLICY "Users can manage their own piggy_bank"
  ON "piggy_bank"
  FOR ALL
  USING (((profile_id = auth.uid()) OR ((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid()))))));
CREATE POLICY "Users can view their own piggy_bank"
  ON "piggy_bank"
  FOR SELECT
  USING (((profile_id = auth.uid()) OR ((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid()))))));
CREATE POLICY "Users can insert own profile"
  ON "profiles"
  FOR INSERT
  WITH CHECK ((auth.uid() = id));
CREATE POLICY "Users can read own profile"
  ON "profiles"
  FOR SELECT
  TO authenticated
  USING ((id = auth.uid()));
CREATE POLICY "Users can update own profile"
  ON "profiles"
  FOR UPDATE
  USING ((auth.uid() = id));
CREATE POLICY "Group members can manage group expenses"
  ON "real_expenses"
  FOR ALL
  USING (((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can manage their own expenses"
  ON "real_expenses"
  FOR ALL
  USING ((profile_id = auth.uid()));
CREATE POLICY "Group members can manage group income entries"
  ON "real_income_entries"
  FOR ALL
  USING (((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can manage their own income entries"
  ON "real_income_entries"
  FOR ALL
  USING ((profile_id = auth.uid()));
CREATE POLICY "Only service role can insert snapshots"
  ON "remaining_to_live_snapshots"
  FOR INSERT
  TO service_role
  WITH CHECK (true);
CREATE POLICY "Users can view their group remaining to live snapshots"
  ON "remaining_to_live_snapshots"
  FOR SELECT
  USING ((group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE ((profiles.id = auth.uid()) AND (profiles.group_id IS NOT NULL)))));
CREATE POLICY "Users can view their own remaining to live snapshots"
  ON "remaining_to_live_snapshots"
  FOR SELECT
  USING ((profile_id = auth.uid()));
CREATE POLICY "Group members can manage group savings projects"
  ON "savings_projects"
  FOR ALL
  USING (((group_id IS NOT NULL) AND (group_id IN ( SELECT profiles.group_id
   FROM profiles
  WHERE (profiles.id = auth.uid())))));
CREATE POLICY "Users can manage their own savings projects"
  ON "savings_projects"
  FOR ALL
  USING ((profile_id = auth.uid()));

