-- Triggers
-- ============================================================================
CREATE TRIGGER update_bank_balances_updated_at BEFORE UPDATE ON public.bank_balances FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER estimated_budgets_sync_group_budget AFTER INSERT OR DELETE OR UPDATE ON public.estimated_budgets FOR EACH ROW EXECUTE FUNCTION sync_group_monthly_budget_estimate();
CREATE TRIGGER group_contributions_sync_real_expense AFTER INSERT OR UPDATE ON public.group_contributions FOR EACH ROW EXECUTE FUNCTION sync_contribution_real_expense();
CREATE TRIGGER groups_budget_contribution_recalc AFTER UPDATE ON public.groups FOR EACH ROW EXECUTE FUNCTION trigger_group_budget_change();
CREATE TRIGGER groups_cleanup_contributions BEFORE DELETE ON public.groups FOR EACH ROW EXECUTE FUNCTION cleanup_group_contributions();
CREATE TRIGGER update_groups_updated_at BEFORE UPDATE ON public.groups FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_monthly_recaps_updated_at BEFORE UPDATE ON public.monthly_recaps FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER profiles_contribution_recalc AFTER INSERT OR DELETE OR UPDATE ON public.profiles FOR EACH ROW EXECUTE FUNCTION trigger_recalculate_contributions();
CREATE TRIGGER update_profiles_updated_at BEFORE UPDATE ON public.profiles FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER real_expenses_credit_balance_on_contribution_delete BEFORE DELETE ON public.real_expenses FOR EACH ROW EXECUTE FUNCTION credit_balance_on_contribution_delete();
CREATE TRIGGER update_savings_projects_updated_at BEFORE UPDATE ON public.savings_projects FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

